import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"OM",currency:"OMR",flag:"🇴🇲",nameEn:"Oman",nameAr:"عُمان",fixedPeg:!1,decimals:3,timezone:"Asia/Muscat",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"}],faqEn:[{q:"What is today's gold price in Oman?",a:"The Omani Rial (OMR) is pegged to the US Dollar at a fixed rate of 0.385 OMR per USD, making it the second most valuable currency in the GCC after the Kuwaiti Dinar. Gold gram prices in OMR appear numerically small but carry significant real value. Prices are updated every 90 seconds."},{q:"Where can I buy gold in Oman?",a:"Muttrah Souq in Muscat is the most famous traditional gold market in Oman, offering a rich selection of jewellery and bullion in a historic setting. Muscat Grand Mall and City Centre Muscat are popular modern alternatives with certified gold retailers."},{q:"What karats are popular in Oman?",a:"22K is the most popular karat for jewellery in Oman, followed by 21K and 18K. Traditional Omani jewellery such as the khanjar-inspired ornaments are typically crafted in high-karat gold. 24K is available for investment."},{q:"Is there VAT on gold in Oman?",a:"Oman introduced a 5% Value Added Tax (VAT) in April 2021. Investment-grade gold meeting standard purity thresholds is generally exempt from VAT, while gold jewellery is subject to the 5% rate. Always confirm with the seller at the point of purchase."}],faqAr:[{q:"ما هو سعر الذهب اليوم في عُمان؟",a:"يرتبط الريال العُماني (OMR) بالدولار الأمريكي بسعر صرف ثابت قدره 0.385 ريال لكل دولار، مما يجعله ثاني أعلى عملات مجلس التعاون الخليجي قيمةً بعد الدينار الكويتي. تبدو أسعار الذهب بالغرام منخفضةً رقمياً لكنها تحمل قيمةً حقيقيةً كبيرة. يتم تحديث الأسعار كل 90 ثانية."},{q:"أين يمكنني شراء الذهب في عُمان؟",a:"يُعدّ سوق مطرح في مسقط الأشهر بين أسواق الذهب التقليدية في عُمان، ويوفر تشكيلةً غنيةً من المجوهرات والسبائك في بيئة تاريخية. كما يُعدّ مسقط جراند مول وسيتي سنتر مسقط بديلين حديثين شهيرين يضمان تجار ذهب معتمدين."},{q:"ما هي العيارات الأكثر شيوعاً في عُمان؟",a:"يُعدّ عيار 22 الأكثر شيوعاً للمجوهرات في عُمان، يليه عيار 21 وعيار 18. تُصنع المجوهرات العُمانية التقليدية كالزينة المستوحاة من الخنجر العُماني عادةً من ذهب عيار مرتفع. ويتوفر عيار 24 للأغراض الاستثمارية."},{q:"هل يُفرض ضريبة القيمة المضافة على الذهب في عُمان؟",a:"طبّقت عُمان ضريبة القيمة المضافة (VAT) بنسبة 5% في أبريل 2021. الذهب الاستثماري الذي يستوفي معايير النقاء القياسية معفى عموماً من ضريبة القيمة المضافة، في حين تخضع مجوهرات الذهب لنسبة الـ5%. يُنصح دائماً بالتأكد من البائع عند الشراء."}]});
